                [PSCustomObject]@{ Name = "Test_B"; Suite = "Suite1"; Status = "Failed";  Duration = 0.3; Message = "Oops" }
                [PSCustomObject]@{ Name = "Test_C"; Suite = "Suite1"; Status = "Passed";  Duration = 1.2; Message = "" }
